mapper.insert:
insert into batch.resource_tag (
    tenant_id, resource_type, resource_code, tag_key, tag_value, created_by
) values (
    #{tenantId}, #{resourceType}, #{resourceCode}, #{tagKey}, #{tagValue}, #{operator}
)
on conflict (tenant_id, resource_type, resource_code, tag_key) do update
    set tag_value  = #{tagValue},
        created_by = #{operator},
        created_at = current_timestamp

